long long n,m,cnt =0,ll=-114514;
const long long INF=1e18;
long long  a[1100][1100],vis[1010][1100],cnt1[1000][1000][3];

long long dfs(int x,int y,bool d){
	if(x<1||y<1||x>n||y>m)return -INF;
	if(cnt1[x][y][d]!=INF)return cnt1[x][y][d];

	if(x == n&&y == m){
		return a[x][y];
	}
	cnt1[x][y][d]=-INF;
	if(d==0)
	{

		cnt1[x][y][d] = max(dfs(x+1,y,d),max(dfs(x,y+1,0),dfs(x,y+1,1))); 


	}
	else{

		cnt1[x][y][d] = max(dfs(x-1,y,d),max(dfs(x,y+1,0),dfs(x,y+1,1))); 
	}
	cnt1[x][y][d]+=a[x][y];
	return cnt1[x][y][d];

}
