	for(int i = 1;i<=n;i++){
		for(int j = 1;j<=m;j++){
			cin>>a[i][j]; 
			cnt1[i][j][0]=cnt1[i][j][1]=INF;
		}
	}


	cout<<max(dfs(1,1,1),dfs(1,1,0));


}

#include<bits/stdc++.h>
using namespace std;
long long n,m;
long long tr[6000005],a[6000005];
int lowbit(int i){
	return i&(-i);
}
void modify(int x,int c){
	for(int i = x;i<=n;i+=lowbit(i)) tr[i] +=c;
} int query(int x){
	int res = 0;
	for(int i = x;i;i -= lowbit(i)) res +=tr[i];
	return res;
} int query (int l,int r){
	return query(r) - query(l - 1);
}
int main()
{	
	cin>>n>>m;
	for(int i = 1;i<=n;i++){
		cin>>a[i];
		modify(i,a[i]);
	}for(int i = 1;i<=m;i++){
		int kk;
		cin>>kk;
		if(kk == 1){
			int x,k;
			cin>>x>>k;
			modify(x,k);
		}if(kk == 2){
			int x,y;
			cin>>x>>y;
			cout<<query(x,y)<<endl;
		}

	}
}

#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+10;
queue <int> kk;
vector <int> a[N];
bool vis[N],vis1[N];
int n,m,ans=0,siz[N],f[N][19],dep[N],d[N];
void ins(int u,int v){
	a[u].push_back(v);
	a[v].push_back(u);
}
void dfs(int u,int f1 = 0){
	f[u][0] = f1;
	for(int i = 1;i<=18;i++){
		f[u][i]=f[f[u][i-1]][i-1];
	}

	dep[u]=dep[f1]+1;	
	for(int v:a[u]){		
		if(v!=f1){
		
		dfs(v,u);
			
		}
	}
	
}void dfs1(int u,int f = -1){
	
	siz[u]=d[u];
	for(int v:a[u]){
			
		if(v!=f){
			
		dfs1(v,u);
			siz[u]+=siz[v];
		}
	}
			
}
int lca(int u , int v){
	if(dep[u]<dep[v])swap(u,v);
	for(int i = 18;i>=0;i--)if(dep[f[u][i]]>=dep[v])u = f[u][i];
	if(u ==v){
		return v;
	}
	for(int i = 18;i>=0;i--)if(f[u][i]!=f[v][i])u = f[u][i],v = f[v][i];
	return f[u][0];
	
}

