int a[501],t[5];
int dp[51][51][51][51];
int DP(int i,int j,int k,int l){
	int mx = 0,p = i+2*j+3*k+4*l+1;
	if(i)mx =max(mx,dp[i-1][j][k][l]);
	if(j)mx =max(mx,dp[i][j-1][k][l]);
	if(k)mx =max(mx,dp[i][j][k-1][l]);
	if(l)mx =max(mx,dp[i][j][k][l-1]);
	return a[p]+mx;
}
