#include<bits/stdc++.h>
using namespace std;
int x[10],y[10],p[10];
double r[10];
inline double dis(int i,int j){
	return sqrt(1.*(x[i]-x[j])*(x[i]-x[j])+1.*(y[i]-y[j])*(y[i]-y[j]));
}

int main(){
	int n;
	cin>>n;
	int x1,y1,x2,y2;
	cin>>x1>>y1>>x2>>y2;
	if(x1>x2){
		swap(x1,x2);
	}if(y1>y2){
		swap(y1,y2);
	}
		
	for(int i = 1;i<=n;i++){
		cin>>x[i]>>y[i];
		x[i]-=x1;
		y[i]-=y1;
		p[i]=i;
		
	}x2-=x1;
	y2-=y1;
	double ans= 0.0;
	do{
		double  s= 0;
		for(int i = 1;i<=n;i++ ){
			int q = p[i];
			double mnr=min(min(x[q],y[q]),min(x2-x[q],y2-y[q]));
			for(int j = 1;j<i;j++){
				mnr=min(mnr,dis(p[i],p[j])-r[j]);
				
				
				
			}r[i]=max(0.,mnr);
			s+=r[i]*r[i];
			
			
		}ans = max(ans,s);
	}while(next_permutation(p+1,p+n+1));
	printf("%0.0f\n",1.*x2*y2-3.14159265358*ans);

}

