#include<bits/stdc++.h>
using namespace std;
int a[1000005],n;
void push(int x){
	a[++n] = x;
	int kk = n;
	while(kk>1&&a[kk/2]>a[kk]){
		swap(a[kk/2],a[kk]);
		kk/=2;	

	}


}
void pop(){
	swap(a[1],a[n--]);
	int x = 1;
	while(x*2<=n){
		int mn = a[x],id =x;
		if(x*2<=n &&a[x*2]<mn)mn = a[x*2],id=x*2;
		if(x*2+1<=n&&a[x*2+1]<mn) mn = a[x*2+1],id = x*2+1;
		if(id == x)break;
		else {
			swap(a[x],a[id]);
			x = id;
		}
	}
}int top(){
	return a[1];
}
int main()
{
	int q;cin>>q;
	while(q--){
		int op;
		cin>>op;
		if(op == 1){
			int kk;
			cin>>kk;
			push(kk);	
		}else if(op == 2){

			cout<<top()<<endl;	
		}else if(op == 3){

			pop();	
		}
	}


}

