ll a[100000],b[100000];
void hb(ll l, ll r){
	if(l>=r){
		return ;
	}
	ll mid = (l+r)/2;
	ll i=l, j=mid+1,tot = l;
	while (i<=mid&&j<=r){
		if(a[i]<=a[j]){
			b[tot++] = a[i];
			i++;
			
		}else {
			b[tot++] = a[j];
			j++;
		}
	}while (i<=mid){
		b[tot++] = a[i];
		i++;
	}while(j<=r){
		b[tot++] = a[j];
		j++;
	}for(int i = l;i<=r;i++){
		a[i]=b[i];
		
	}return;
	
}
void zh(ll l,ll r){
	if(l<r){
		int mid = (l+r)/2;
		zh(l,mid);
		zh(mid+1,r);
		hb(l,r);
	}
}
