int main(){
	int n,k; //总共的猴子
	int a[1000000000]; //猴子的死活 
	// a[5]=1代表 5号猴子死了;  a[3]=0 
	int cnt=0,index=0,dead=0;
	//cnt代表报数 index当前猴子的序号 dead死掉的猴子数
	
	//输入并处理数据
	cin>>n>>k; 
	for(int i=1;i<=n;i++) a[i] = 0; //所有猴子都活着
	
	//开始游戏
	while(dead<n-1){
		//猴子序号改变
		index++; 
		if(index>n){ //为了形成环状循环 
			index = 1;
		}
		//判断猴子死活
		if(a[index]==0){
			//报数
			cnt++;
			if(cnt==k){ //如果数到3 
				a[index] = 1; //当前猴子淘汰
				cnt = 0; 
				dead ++;  //淘汰数变大 
			} 
		} 	 
	} 
	
	//找到幸存的猴子
	for(int i=1;i<=n;i++){
		if(a[i]==0) cout<<i; 
	} 
	 
}

