int main()
{	
	cin>>n;
	while(n--){
		long long sum = 0;
		b[1] = b[2] = b[3] = 0;

		int t;
		cin>>t;
		for(int i = 1;i<=t;i++){
			cin>>a[i].x>>a[i].y>>a[i].z;
		}for(int i = 1;i<=t;i++){
			int p = a[i].x;
			int q = a[i].y;
			int o = a[i].z;
			int maxx = max(max(p,q),o);
			if(maxx == p){
				b[1]++;
				d[i] = 1;
				sum+=p;
			}
			else if(maxx == q){
				b[2]++;
				d[i]= 2;
				sum+=q;
			}

			else if(maxx == o){
				b[3]++;
				d[i]=3;
				sum+=o;
			}
		}if(b[2]>t/2){
			for(int i = 1;i<=t;i++){
				swap(a[i].x,a[i].y);
				if(d[i]==2)d[i]=1;
				else if(d[i]==1)d[i]=2;
			}swap(b[2],b[1]);
		}if(b[3]>t/2){
			for(int i = 1;i<=t;i++){
				swap(a[i].z,a[i].x);
				if(d[i]==3)d[i]=1;
				else if(d[i]==1)d[i]=3;
			}swap(b[3],b[1]);
		}for(int i = 1;i<=t;i++){
			int u = a[i].x-a[i].y;
			int v = a[i].x-a[i].z;

			kk[i] = min(u,v);

		}sort(&kk[1],&kk[t+1]);
		for(int i = 1;i<=b[1]-t/2;i++){
			sum-=kk[i];
		}cout<<sum<<endl;

	}
}

