		vis[i] = 0;
	}int ans=0;
	for(int i = n;i>=1;i--){
		if(!vis[i]){
			for(int j = i - 1;j>=1;j--){
				if((i&j) == 0){
					while(i>j){
						G[++ans].push_back(i);
						G[ans].push_back(j);
						vis[i] = 1;
						vis[j] = 1;
						i--;
						j++;
					}break;
				}
			}
		}
		ans++;
